class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        n = len(s)
        dp = [[float('inf')] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(1, n + 1):
            for j in range(1, min(i, k) + 1):
                for prev in range(i):
                    cost = dp[prev][j - 1] + self.get_cost(s, prev, i)
                    dp[i][j] = min(dp[i][j], cost)

        return dp[n][k]

    def get_cost(self, s, start, end):
        if end - start == 1:
            return 0

        counts = {}
        for i in range(start, end):
            idx = (i - start) % (end - start)
            counts[idx] = counts.get(idx, set())
            counts[idx].add(s[i])

        cost = 0
        for idx in counts:
            cost += max(0, len(counts[idx]) - 1)

        return cost
